	"<td class=\"api-example\">{\"ok\":true,\"data\":{\"field\":\"bitrate\",\"value\":4000}}</td></tr>\n\n<tr><td class=\"api-method\">GET</td><td class=\"api-path\">/api/v1/dual/set?gop=<i>N</i></td><td class=\"api-desc\">Set dual channel GOP interval in seconds</td><td class=\"api-example\">{\"ok\":true,\"data\":{\"field\":\"gop\",\"value\":1.0,\"frames\":60}}</td></tr>\n\n<tr><td class=\"api-method\">GET</td><td class=\"api-path\">/api/v1/dual/idr</td><td class=\"api-desc\">Force IDR keyframe on d"
	"ual channel</td><td class=\"api-example\">{\"ok\":true,\"data\":{\"idr\":true}}</td></tr>\n\n</tbody></table>\n\n</div>\n\n</div>\n\n<!-- Tab: Image Quality -->\n\n<div class=\"tab-content\" id=\"tab-iq\">\n\n  <div class=\"iq-intro\">\n\n    The IQ system provides direct access to <b>SigmaStar ISP</b> image processing parameters via runtime dlopen of <code>libmi_isp.so</code>. Parameters are organized by category and can be queried and modified live without restarting the pipeline. Changes take"
	" effect on the next frame.\n\n  </div>\n\n  <h3 style=\"font-size:.85rem;color:var(--text-bright);margin:0 0 .6rem\">Set Parameter</h3>\n\n  <div class=\"iq-set-form\">\n\n    <input type=\"text\" id=\"iq-param-name\" placeholder=\"Parameter name (e.g. contrast)\">\n\n    <input type=\"text\" id=\"iq-param-value\" placeholder=\"Value (or 1,2,3 for arrays)\">\n\n    <button class=\"btn btn-apply\" onclick=\"setIQParam()\">Set</button>\n\n  </div>\n\n  <h3 style=\"font-size:.85rem;color:var(--text"
	"-bright);margin:.5rem 0 .6rem\">Parameter Categories</h3>\n\n  <p style=\"font-size:.75rem;color:var(--text-dim);margin-bottom:.6rem\">Click a parameter to select it for editing above.</p>\n\n  <div id=\"iq-categories\"></div>\n\n  <h3 style=\"font-size:.85rem;color:var(--text-bright);margin:1.2rem 0 .6rem\">Query Parameters</h3>\n\n  <div class=\"iq-controls\">\n\n    <button class=\"iq-btn\" onclick=\"queryIQ()\">Query All Parameters</button>\n\n  </div>\n\n  <div class=\"iq-result\" id=\"iq-p"
	"arams-result\">\n\n    <pre id=\"iq-params-pre\"></pre>\n\n  </div>\n\n</div>\n\n<script>\n\n/* ── State ── */\n\nlet serverConfig = {};\n\nlet localConfig = {};\n\nlet capabilities = {};\n\nconst changedFields = new Set();\n\nconst TOOLTIPS = {\n\n'system.webPort':'HTTP server port. Change requires restart. Default: 80',\n\n'system.overclockLevel':'CPU overclock level (0-2). Higher = more performance but more heat. Default: 1',\n\n'system.verbose':'Enable detailed logging to stdout. Useful for "
	"debugging. Default: off',\n\n'sensor.index':'Sensor hardware index. -1 = auto-detect. Only change if multiple sensors installed',\n\n'sensor.mode':'Sensor resolution/fps mode. -1 = auto (highest). Sensor-specific values',\n\n'sensor.unlockEnabled':'Enable sensor unlock sequence on startup. Required for some sensors. Default: on',\n\n'sensor.unlockCmd':'I2C command byte for sensor unlock. Hex value. Default: 0x23',\n\n'sensor.unlockReg':'I2C register for sensor unlock. Hex value. Default: 0x300a'"
	",\n\n'sensor.unlockValue':'Value written to unlock register. Hex value. Default: 0x80',\n\n'sensor.unlockDir':'I2C direction for unlock (0=write, 1=read). Default: 0',\n\n'isp.sensorBin':'Path to ISP calibration binary (.bin). Empty = use built-in defaults',\n\n'isp.exposure':'Manual exposure time in milliseconds. 0 = auto exposure. Applied live',\n\n'isp.gainMax':'Maximum sensor gain limit. 0 = use ISP default. Reduces noise in dark scenes',\n\n'isp.awbMode':'White balance mode. auto = automati"
	"c, ct_manual = fixed color temperature',\n\n'isp.awbCt':'Color temperature in Kelvin when awb_mode=ct_manual. 2000-10000. Default: 5500',\n\n'image.mirror':'Flip image horizontally. Requires restart',\n\n'image.flip':'Flip image vertically. Requires restart',\n\n'image.rotate':'Rotate image (0 or 180 degrees). Requires restart',\n\n'video0.codec':'Video codec. Currently only h265 is supported',\n\n'video0.rcMode':'Rate control: cbr=constant bitrate, vbr=variable, avbr=adaptive variable, qvbr=qua"
	"lity VBR',\n\n'video0.fps':'Target frames per second. Clamped to sensor maximum. Applied live',\n\n'video0.size':'Resolution as WxH (e.g. 1920x1080). Accepts shortcuts: 720p, 1080p, 4MP. Requires restart',\n\n'video0.bitrate':'Target bitrate in kbps (1-200000). Higher = better quality, more bandwidth. Applied live',\n\n'video0.gopSize':'GOP interval in seconds. 0 = all-intra (every frame is keyframe). Applied live',\n\n'video0.qpDelta':'I/P frame QP delta (-12 to +12). Negative = better I-frame "
	"quality. Applied live',\n\n'video0.frameLost':'Drop frames when encoder exceeds bitrate threshold. Safety net for bandwidth. Requires restart',\n\n'outgoing.enabled':'Enable video output streaming. When disabled, encoder runs at idle FPS. Applied live',\n\n'outgoing.server':'Destination URI (e.g. udp://192.168.1.1:5600). Applied live',\n\n'outgoing.streamMode':'Transport protocol: rtp (standard). Requires restart',\n\n'outgoing.maxPayloadSize':'Max RTP payload bytes. 1400 is safe for most networ"
	"ks. Requires restart',\n\n'outgoing.connectedUdp':'Use connected UDP socket for lower kernel overhead. Default: on. Requires restart',\n\n'outgoing.audioPort':'UDP port for audio stream. Default: 5601. Requires restart',\n\n'outgoing.sidecarPort':'UDP port for sidecar metadata. Default: 5602. Requires restart',\n\n'audio.mute':'Mute audio capture. Applied live. No-op if audio not active',\n\n'fpv.roiEnabled':'Enable ROI (Region of Interest) \\u2014 allocate more bits to center of frame. Applied "
	"live',\n\n'fpv.roiQp':'ROI QP adjustment (-30 to +30). Negative = higher quality in center. 0 = disabled. Applied live',\n\n'fpv.roiSteps':'Number of horizontal ROI bands (1-4). More steps = smoother gradient. Applied live',\n\n'fpv.roiCenter':'Center region fraction (0.1-0.9). Smaller = tighter center focus. Applied live',\n\n'fpv.noiseLevel':'3D noise reduction level (0-7). Higher = more NR. 0 = off. Requires restart'\n\n};\n\nconst ENUMS = {\n\n'video0.codec':['h265'],\n\n'video0.rcMode':['cb"
	"r','vbr','avbr','qvbr'],\n\n'isp.awbMode':['auto','ct_manual']\n\n};\n\nconst SECTIONS = [\n\n{id:'system',title:'System',keys:['system.webPort','system.overclockLevel','system.verbose']},\n\n{id:'sensor',title:'Sensor',keys:['sensor.index','sensor.mode','sensor.unlockEnabled','sensor.unlockCmd','sensor.unlockReg','sensor.unlockValue','sensor.unlockDir']},\n\n{id:'isp',title:'ISP',keys:['isp.sensorBin','isp.exposure','isp.gainMax','isp.awbMode','isp.awbCt']},\n\n{id:'image',title:'Image',keys:['"
	"image.mirror','image.flip','image.rotate']},\n\n{id:'video0',title:'Video',keys:['video0.codec','video0.rcMode','video0.fps','video0.size','video0.bitrate','video0.gopSize','video0.qpDelta','video0.frameLost']},\n\n{id:'outgoing',title:'Outgoing',keys:['outgoing.enabled','outgoing.server','outgoing.streamMode','outgoing.maxPayloadSize','outgoing.connectedUdp','outgoing.audioPort','outgoing.sidecarPort']},\n\n{id:'audio',title:'Audio',keys:['audio.mute']},\n\n{id:'fpv',title:'FPV',keys:['fpv.roiE"
	"nabled','fpv.roiQp','fpv.roiSteps','fpv.roiCenter','fpv.noiseLevel']}\n\n];\n\n/* ── API helpers ── */\n\nasync function api(path){\n\n  const r = await fetch(path);\n\n  return r.json();\n\n}\n\nfunction toast(msg, ok=true){\n\n  const el = document.createElement('div');\n\n  el.className = 'toast ' + (ok ? 'toast-ok' : 'toast-err');\n\n  el.textContent = msg;\n\n  document.getElementById('toasts').appendChild(el);\n\n  setTimeout(() => el.remove(), 3000);\n\n}\n\n/* ── Tabs ── */\n\nfunction s"
	"witchTab(id){\n\n  document.querySelectorAll('.tab').forEach((t,i) => {\n\n    const ids = ['settings','api','iq'];\n\n    t.classList.toggle('active', ids[i] === id);\n\n  });\n\n  document.querySelectorAll('.tab-content').forEach(c => c.classList.remove('active'));\n\n  document.getElementById('tab-'+id).classList.add('active');\n\n}\n\n/* ── Flatten nested config into dot notation ── */\n\nfunction flattenConfig(obj, prefix=''){\n\n  const out = {};\n\n  for(const [k,v] of Object.entries(obj)"
	"){\n\n    const key = prefix ? prefix+'.'+k : k;\n\n    if(v && typeof v === 'object' && !Array.isArray(v)){\n\n      Object.assign(out, flattenConfig(v, key));\n\n    } else {\n\n      out[key] = v;\n\n    }\n\n  }\n\n  return out;\n\n}\n\n/* ── Determine field type ── */\n\nfunction fieldType(key, val){\n\n  if(key === 'video0.size') return 'size';\n\n  if(ENUMS[key]) return 'enum';\n\n  if(typeof val === 'boolean') return 'bool';\n\n  if(typeof val === 'number'){\n\n    if(Number.isInteger(va"
	"l)) return 'int';\n\n    return 'double';\n\n  }\n\n  return 'string';\n\n}\n\n/* ── Render settings form ── */\n\nfunction renderSettings(){\n\n  const form = document.getElementById('settings-form');\n\n  form.innerHTML = '';\n\n  for(const sec of SECTIONS){\n\n    const div = document.createElement('div');\n\n    div.className = 'section';\n\n    div.innerHTML = `<div class=\"section-header\" onclick=\"this.parentElement.classList.toggle('collapsed')\">\n\n      <h3>${sec.title}</h3><span cla"
	"ss=\"section-chevron\">\\u25BC</span></div><div class=\"section-body\"></div>`;\n\n    const body = div.querySelector('.section-body');\n\n    for(const key of sec.keys){\n\n      if(!(key in localConfig)) continue;\n\n      const val = localConfig[key];\n\n      const mut = capabilities[key]?.mutability || 'restart_required';\n\n      const ft = fieldType(key, val);\n\n      const row = document.createElement('div');\n\n      row.className = 'field';\n\n      row.id = 'field-'+key;\n\n      con"
	"st label = key.split('.').pop().replace(/_/g,' ');\n\n      const badgeClass = mut === 'live' ? 'badge-live' : 'badge-restart';\n\n      const badgeText = mut === 'live' ? 'LIVE' : 'RESTART';\n\n      let input = '';\n\n      if(ft === 'bool'){\n\n        input = `<label class=\"toggle\"><input type=\"checkbox\" data-key=\"${key}\" ${val?'checked':''} onchange=\"fieldChanged('${key}',this.checked)\"><span class=\"toggle-track\"></span></label>`;\n\n      } else if(ft === 'enum'){\n\n        cons"
	"t opts = ENUMS[key].map(o => `<option value=\"${o}\" ${o===String(val)?'selected':''}>${o}</option>`).join('');\n\n        input = `<select data-key=\"${key}\" onchange=\"fieldChanged('${key}',this.value)\">${opts}</select>`;\n\n      } else if(ft === 'double'){\n\n        input = `<input type=\"number\" step=\"0.1\" data-key=\"${key}\" value=\"${val}\" onchange=\"fieldChanged('${key}',parseFloat(this.value))\">`;\n\n      } else if(ft === 'int'){\n\n        input = `<input type=\"number\" data-"
	"key=\"${key}\" value=\"${val}\" onchange=\"fieldChanged('${key}',parseInt(this.value))\">`;\n\n      } else {\n\n        input = `<input type=\"text\" data-key=\"${key}\" value=\"${val}\" onchange=\"fieldChanged('${key}',this.value)\">`;\n\n      }\n\n      row.innerHTML = `<div class=\"field-label\" title=\"${(TOOLTIPS[key]||'').replace(/\"/g,'&quot;')}\">${label} <span class=\"badge ${badgeClass}\">${badgeText}</span></div><div>${input}</div>`;\n\n      body.appendChild(row);\n\n    }\n\n    f"
	"orm.appendChild(div);\n\n  }\n\n  document.getElementById('settings-loading').style.display = 'none';\n\n  form.style.display = 'block';\n\n  document.getElementById('settings-actions').style.display = 'flex';\n\n}\n\nfunction fieldChanged(key, val){\n\n  localConfig[key] = val;\n\n  const row = document.getElementById('field-'+key);\n\n  const sv = serverConfig[key];\n\n  if(String(val) !== String(sv)){\n\n    changedFields.add(key);\n\n    row?.classList.add('changed');\n\n  } else {\n\n    ch"
	"angedFields.delete(key);\n\n    row?.classList.remove('changed');\n\n  }\n\n  updateButtons();\n\n}\n\nfunction updateButtons(){\n\n  const n = changedFields.size;\n\n  document.getElementById('btn-apply').disabled = n === 0;\n\n  document.getElementById('change-count').textContent = n ? n + ' change' + (n>1?'s':'') : '';\n\n}\n\n/* ── Apply / Restart / Discard ── */\n\nasync function applyChanges(){\n\n  const btn = document.getElementById('btn-apply');\n\n  btn.disabled = true;\n\n  btn.textCo"
	"ntent = 'Applying...';\n\n  let ok = 0, fail = 0;\n\n  for(const key of [...changedFields]){\n\n    try{\n\n      const val = localConfig[key];\n\n      const r = await api('/api/v1/set?'+encodeURIComponent(key)+'='+encodeURIComponent(val));\n\n      if(r.ok){\n\n        serverConfig[key] = val;\n\n        changedFields.delete(key);\n\n        document.getElementById('field-'+key)?.classList.remove('changed');\n\n        ok++;\n\n      } else {\n\n        toast(key+': '+(r.error?.message||'faile"
	"d'), false);\n\n        fail++;\n\n      }\n\n    } catch(e){\n\n      toast(key+': '+e.message, false);\n\n      fail++;\n\n    }\n\n  }\n\n  if(ok) toast(ok+' field'+(ok>1?'s':'')+' applied');\n\n  btn.textContent = 'Apply Changes';\n\n  updateButtons();\n\n}\n\nasync function saveAndRestart(){\n\n  await applyChanges();\n\n  toast('Restarting pipeline...');\n\n  await api('/api/v1/restart');\n\n}\n\nfunction discardChanges(){\n\n  localConfig = {...serverConfig};\n\n  changedFields.clear();\n"
	"\n  renderSettings();\n\n  updateButtons();\n\n  toast('Changes discarded');\n\n}\n\nasync function restoreDefaults(){\n\n  if(!confirm('Restore all settings to defaults and restart the pipeline? This discards any in-memory changes and reloads the on-disk configuration.')) return;\n\n  toast('Restoring defaults and restarting...');\n\n  try{\n\n    await api('/api/v1/restart');\n\n    setTimeout(async ()=>{\n\n      try{\n\n        const cfgR = await api('/api/v1/config');\n\n        if(cfgR.ok)"
	"{\n\n          serverConfig = flattenConfig(cfgR.data.config);\n\n          localConfig = {...serverConfig};\n\n        }\n\n        changedFields.clear();\n\n        renderSettings();\n\n        updateButtons();\n\n        toast('Defaults restored');\n\n      }catch(e){ toast('Reload failed: '+e.message, false); }\n\n    }, 2000);\n\n  }catch(e){ toast('Restart failed: '+e.message, false); }\n\n}\n\n/* ── Telemetry polling ── */\n\nasync function pollTelemetry(){\n\n  try{\n\n    const [fps, re"
	"c] = await Promise.all([\n\n      api('/api/v1/fps/live').catch(()=>null),\n\n      api('/api/v1/record/status').catch(()=>null)\n\n    ]);\n\n    if(fps?.ok) document.getElementById('tbar-fps').textContent = fps.data.fps;\n\n    if(rec?.ok){\n\n      const dot = document.getElementById('tbar-rec');\n\n      dot.className = 'tbar-dot ' + (rec.data.active ? 'on' : 'off');\n\n    }\n\n  }catch(e){}\n\n}\n\n/* ── IQ Tab ── */\n\nasync function queryIQ(){\n\n  const el = document.getElementById('iq-"
	"params-result');\n\n  const pre = document.getElementById('iq-params-pre');\n\n  el.classList.add('visible');\n\n  pre.textContent = 'Loading...';\n\n  try{\n\n    const r = await api('/api/v1/iq');\n\n    if(r.ok){\n\n      if(Array.isArray(r.data)){\n\n        let txt = 'Parameter                  Value     Type\\\n' + '\\u2500'.repeat(50) + '\\\n';\n\n        for(const p of r.data){\n\n          txt += (p.param||'').padEnd(26) + String(p.value ?? '-').padEnd(10) + (p.type||'') + '\\\n';\n\n  "
	"      }\n\n        pre.textContent = txt;\n\n      } else {\n\n        pre.textContent = JSON.stringify(r.data, null, 2);\n\n      }\n\n    } else pre.textContent = JSON.stringify(r, null, 2);\n\n  }catch(e){ pre.textContent = 'Error: '+e.message; }\n\n}\n\nfunction selectIQParam(name){\n\n  document.getElementById('iq-param-name').value = name;\n\n  document.getElementById('iq-param-value').value = '';\n\n  document.getElementById('iq-param-value').focus();\n\n}\n\n/* Params with multi-field de"
	"scriptors — sub-fields shown as dot-notation chips */\nconst IQ_FIELDS = {\n  colortrans: ['y_ofst','u_ofst','v_ofst','matrix'],\n  r2y: ['matrix','add_y16'],\n  obc: ['val_r','val_gr','val_gb','val_b'],\n  obc_p1: ['val_r','val_gr','val_gb','val_b'],\n  demosaic: ['dir_thrd','edge_smooth_y','edge_smooth_c'],\n  false_color: ['freq_thrd','edge_score_thrd','chroma_thrd_max','chroma_thrd_mid','chroma_thrd_min','strength_mid','strength_min'],\n  crosstalk: ['strength','strength_by_y','threshold','o"
	"ffset'],\n  wdr_curve_adv: ['slope','trans_point_0','trans_point_1','saturated_point','curve_mode_sel']\n};\n\nconst IQ_CATEGORIES = [\n  {name:'Image Quality',desc:'Core image appearance controls. Most take 0-255 range values',\n   params:['lightness','contrast','brightness','saturation','sharpness','hsv']},\n  {name:'Noise Reduction',desc:'3D and 2D temporal/spatial noise reduction. _adv variants offer fine-grained control',\n   params:['nr3d','nr3d_ex','nr3d_p1','nr_despike','nr_luma','nr_lum"
	"a_adv','nr_chroma','nr_chroma_adv']},\n  {name:'Color & Corrections',desc:'Color processing pipeline: demosaicing, matrix transforms, false color suppression',\n   params:['false_color','crosstalk','demosaic','rgb_matrix','colortrans','r2y','dynamic_dp','dp_cluster','obc']},\n  {name:'Dynamic Range',desc:'Wide dynamic range, post-filter compensation, HDR tone mapping',\n   params:['wdr','wdr_curve_adv','wdr_curve_full','pfc','pfc_ex','hdr','hdr_ex','shp_ex']},\n  {name:'Lens Calibration',desc:'L"
	"ens shading correction, auto-LSC, optical black calibration',\n   params:['lsc','lsc_ctrl','alsc','alsc_ctrl','obc_p1','stitch_lpf']},\n  {name:'Gamma & LUT',desc:'Tone curve and lookup table adjustments',\n   params:['rgb_gamma','yuv_gamma']},\n  {name:'Toggles',desc:'Binary feature switches: grayscale mode, defogging, fixed-pattern noise',\n   params:['color_to_gray','defog','fpn','iq_mode']},\n  {name:'AE Control',desc:'Auto-exposure engine parameters',\n   params:['ae_ev_comp','ae_mode','ae_"
	"state','ae_flicker','ae_flicker_ex','ae_win_wgt_type','ae_manual_expo','ae_expo_limit','ae_stabilizer','ae_rgbir','ae_hdr']},\n  {name:'AWB Control',desc:'Auto white-balance engine parameters',\n   params:['awb_attr_ex','awb_multi_ls','awb_stabilizer']}\n];\n\nfunction renderIQCategories(){\n  const container = document.getElementById('iq-categories');\n  container.innerHTML = '';\n  for(const cat of IQ_CATEGORIES){\n    const sec = document.createElement('div');\n    sec.className = 'iq-cat-sec"
	"tion collapsed';\n    let chipsHtml = '';\n    for(const p of cat.params){\n      const fields = IQ_FIELDS[p];\n      if(fields){\n        chipsHtml += '<div style=\"margin:2px 0\"><span class=\"iq-param-chip\" style=\"background:var(--accent-glow);border-color:var(--accent);color:var(--accent)\" onclick=\"selectIQParam(\\''+p+'\\')\">'+p+'</span> ';\n        chipsHtml += fields.map(f =>\n          '<span class=\"iq-param-chip\" onclick=\"selectIQParam(\\''+p+'.'+f+'\\')\">'+f+'</span>'\n       "
	" ).join('');\n        chipsHtml += '</div>';\n      } else {\n        chipsHtml += '<span class=\"iq-param-chip\" onclick=\"selectIQParam(\\''+p+'\\')\">'+p+'</span> ';\n      }\n    }\n    sec.innerHTML = '<div class=\"iq-cat-header\" onclick=\"this.parentElement.classList.toggle(\\'collapsed\\')\">'+\n      '<h4>'+cat.name+'</h4><span class=\"desc\">'+cat.desc+'</span>'+\n      '<span class=\"iq-cat-chevron\">\\u25BC</span></div>'+\n      '<div class=\"iq-cat-body\">'+chipsHtml+'</div>';\n    "
	"container.appendChild(sec);\n  }\n\n}\n\nasync function setIQParam(){\n\n  const name = document.getElementById('iq-param-name').value.trim();\n\n  const value = document.getElementById('iq-param-value').value.trim();\n\n  if(!name || value === ''){toast('Enter parameter name and value',false);return;}\n\n  try{\n\n    const r = await api('/api/v1/iq/set?'+encodeURIComponent(name)+'='+value);\n\n    if(r.ok) toast(name+' = '+value);\n\n    else toast(r.error?.message || 'Set failed', false);\n\n"
	"  }catch(e){ toast(e.message, false); }\n\n}\n\n/* ── Export config ── */\n\nasync function exportConfig(){\n\n  try{\n\n    const r = await api('/api/v1/config');\n\n    const blob = new Blob([JSON.stringify(r.ok?r.data.config:r, null, 2)], {type:'application/json'});\n\n    const a = document.createElement('a');\n\n    a.href = URL.createObjectURL(blob);\n\n    a.download = 'waybeam_venc_config.json';\n\n    a.click();\n\n    URL.revokeObjectURL(a.href);\n\n    toast('Config exported');\n\n  }"
	"catch(e){ toast('Export failed: '+e.message, false); }\n\n}\n\n/* ── Init ── */\n\nasync function init(){\n\n  try{\n\n    const [cfgR, capR, verR] = await Promise.all([\n\n      api('/api/v1/config'),\n\n      api('/api/v1/capabilities'),\n\n      api('/api/v1/version')\n\n    ]);\n\n    if(cfgR.ok){\n\n      serverConfig = flattenConfig(cfgR.data.config);\n\n      localConfig = {...serverConfig};\n\n    }\n\n    if(capR.ok){\n\n      const raw = capR.data.fields || {};\n\n      capabilities = "
	"{};\n\n      for(const [k,v] of Object.entries(raw)){\n\n        capabilities[k] = v;\n\n        const parts = k.split('.');\n\n        const camel = parts[0]+'.'+parts.slice(1).join('.').replace(/_([a-z])/g,(_,c)=>c.toUpperCase());\n\n        if(camel !== k) capabilities[camel] = v;\n\n      }\n\n    }\n\n    if(verR.ok){\n\n      document.getElementById('tbar-version').innerHTML = 'v<b>'+verR.data.app_version+'</b>';\n\n      document.getElementById('tbar-backend').innerHTML = '<b>'+verR.data."
	"backend+'</b>';\n\n    }\n\n    renderSettings();\n\n    renderIQCategories();\n\n    pollTelemetry();\n\n    setInterval(pollTelemetry, 2000);\n\n  }catch(e){\n\n    document.getElementById('settings-loading').textContent = 'Failed to load: '+e.message;\n\n  }\n\n}\n\ninit();\n\n</script>\n\n</body>\n\n</html>\n\n";

static int handle_dashboard(int fd, const HttpRequest *req, void *ctx)
{
	(void)req; (void)ctx;
	return httpd_send_html(fd, 200, dashboard_html);
}

int venc_webui_register(void)
{
	return venc_httpd_route("GET", "/", handle_dashboard, NULL);
}
